import React, { useEffect, useRef } from "react";
import { init } from "ityped";

export default function Intro() {
  const textRef = useRef();

  useEffect(() => {
    init(textRef.current, {
      backDelay: 1500,
      backSpeed: 60,
      showCursor: true,
      strings: ["Developer"]
    });
  }, []);

  return (
    <div
      style={{
        backgroundColor: "#f0f0f0",
        display: "flex",
        flexDirection: "row",
        padding: "80px 40px",
        justifyContent: "space-between",
        alignItems: "center",
        height: "100vh",
        "@media screen and (max-width: 768px)": {
          flexDirection: "column",
          alignItems: "center",
        }
      }}
      className="intro"
      id="intro"
    >
      {/* Left Section */}
      <div
        style={{
          flex: "0.5",
          overflow: "hidden",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          "@media screen and (max-width: 768px)": {
            marginBottom: "20px"
          }
        }}
        className="left"
      >
        <div
          style={{
            maxWidth: "500px",
            width: "100%",
            height: "auto",
            position: "relative",
            borderRadius: "20px",
            overflow: "hidden",
            boxShadow: "0px 10px 30px rgba(0, 0, 0, 0.1)",
          }}
          className="imgContainer"
        >
          <img
            src="assets/woman.png"
            alt="woman"
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
              transition: "transform 0.5s ease",
            }}
          />
        </div>
      </div>

      {/* Right Section */}
      <div
        style={{
          flex: "0.5",
          position: "relative",
          textAlign: "center",
          "@media screen and (max-width: 768px)": {
            flex: "1",
          },
        }}
        className="right"
      >
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            alignItems: "center",
          }}
          className="wrapper"
        >
          <h2
            style={{
              fontSize: "40px",
              fontWeight: "600",
              color: "#333",
              marginBottom: "10px",
              letterSpacing: "2px",
              textTransform: "uppercase",
            }}
          >
            Hi There, I'm
          </h2>
          <h1
            style={{
              fontSize: "80px",
              margin: "10px 0",
              fontWeight: "700",
              color: "#222",
              lineHeight: "1.1",
              letterSpacing: "3px",
            }}
          >
            Soumya
          </h1>
          <h3
            style={{
              fontSize: "35px",
              fontWeight: "500",
              color: "#555",
              margin: "20px 0",
              "@media screen and (max-width: 768px)": {
                fontSize: "25px",
              },
            }}
          >
            I'm a{" "}
            <span
              ref={textRef}
              style={{
                fontSize: "inherit",
                color: "#E91E63",
                fontWeight: "600",
                letterSpacing: "1px",
              }}
            ></span>
          </h3>
        </div>
        <a
          href="#portfolio"
          style={{
            position: "absolute",
            bottom: "10px",
            left: "50%",
            transform: "translateX(-50%)",
            textDecoration: "none",
          }}
        >
          <img
            src="assets/down.png"
            alt="scroll down"
            style={{
              width: "40px",
              animation: "arrowBlink 2s infinite",
              cursor: "pointer",
            }}
          />
        </a>
      </div>
    </div>
  );
}
